import { chromium } from 'playwright';

const STORYBOOK_URL = 'http://localhost:6008';

async function main() {
  const browser = await chromium.launch({ headless: true });
  const page = await browser.newPage({ viewport: { width: 1400, height: 900 } });

  // Navigate to an SDUI Demo story to test the JSON editor
  await page.goto(`${STORYBOOK_URL}/?path=/story/sdui-demo-voucher-screens--form`, { waitUntil: 'networkidle' });
  await page.waitForTimeout(3000);

  // Screenshot the full page with editor panel (light mode)
  await page.screenshot({ path: '.storybook/screenshots/editor-light-mode.png', fullPage: false });
  console.log('Light mode screenshot saved');

  // Try dark mode via media emulation
  await page.emulateMedia({ colorScheme: 'dark' });
  await page.waitForTimeout(2000);
  await page.screenshot({ path: '.storybook/screenshots/editor-dark-mode.png', fullPage: false });
  console.log('Dark mode screenshot saved');

  // Check the editor panel specifically - click on it to ensure it's visible
  const jsonEditorTab = page.locator('button:has-text("JSON Editor")');
  if (await jsonEditorTab.isVisible()) {
    await jsonEditorTab.click();
    await page.waitForTimeout(1000);
    await page.screenshot({ path: '.storybook/screenshots/editor-panel-active.png', fullPage: false });
    console.log('Panel active screenshot saved');
  }

  // Check if editor has content (not empty)
  const editorContent = await page.locator('.cm-content').textContent().catch(() => '');
  console.log(`Editor content length: ${editorContent?.length ?? 0}`);
  console.log(`Editor has content: ${(editorContent?.length ?? 0) > 10}`);

  // Back to light mode for another check
  await page.emulateMedia({ colorScheme: 'light' });
  await page.waitForTimeout(1000);

  // Navigate to Summary story to test another story
  await page.goto(`${STORYBOOK_URL}/?path=/story/sdui-demo-voucher-screens--summary`, { waitUntil: 'networkidle' });
  await page.waitForTimeout(3000);
  await page.screenshot({ path: '.storybook/screenshots/editor-summary-story.png', fullPage: false });
  console.log('Summary story screenshot saved');

  await browser.close();
  console.log('Done!');
}

main().catch(e => { console.error(e); process.exit(1); });

