  await page.screenshot({ path: '.storybook/screenshots/editor-dark-full-hires.png', fullPage: false });
  console.log('Dark mode full hi-res saved');

  await browser.close();
  console.log('Done!');
}

main().catch(e => { console.error(e); process.exit(1); });

