import { chromium } from 'playwright';

const STORYBOOK_URL = 'http://localhost:6008';

async function main() {
  const browser = await chromium.launch({ headless: true });
  const page = await browser.newPage({ viewport: { width: 1600, height: 1000 } });

  // Navigate to SDUI VoucherDemo Form story
  await page.goto(`${STORYBOOK_URL}/?path=/story/sdui-voucherdemo--form`, { waitUntil: 'networkidle' });
  await page.waitForTimeout(4000);

  // Light mode screenshot
  await page.screenshot({ path: '.storybook/screenshots/editor-final-light.png', fullPage: false });
  console.log('Light mode saved');

  // Check editor content
  const content = await page.locator('.cm-content').textContent().catch(() => '');
  console.log(`Editor content length: ${content?.length ?? 0}`);

  // Check for syntax highlighting classes
  const hasHighlighting = await page.evaluate(() => {
    const el = document.querySelector('.cm-content');
    if (!el) return false;
    return el.querySelectorAll('.cm-string, .ͼe, .ͼd, .ͼb').length > 0
      || el.innerHTML.includes('class=');
  });
  console.log(`Has syntax highlighting: ${hasHighlighting}`);

  // Navigate to FullFlow to test a more complex story
  await page.goto(`${STORYBOOK_URL}/?path=/story/sdui-voucherdemo--full-flow`, { waitUntil: 'networkidle' });
  await page.waitForTimeout(4000);
  await page.screenshot({ path: '.storybook/screenshots/editor-final-fullflow.png', fullPage: false });

  const fullflowContent = await page.locator('.cm-content').textContent().catch(() => '');
  console.log(`FullFlow editor content length: ${fullflowContent?.length ?? 0}`);

  await browser.close();
  console.log('Done!');
}

main().catch(e => { console.error(e); process.exit(1); });

